class Solution:
    def solve(self, graph: dict) -> bool:
        visited = {node: False for node in graph}
        for node in graph:
            if not self._dfs(node, visited, set()):
                return False
        return True

    def _dfs(self, node, visited, current_path):
        if node in current_path:
            return False
        visited[node] = True
        current_path.add(node)
        for neighbor in graph[node]:
            if not self._dfs(neighbor, visited, current_path):
                return False
        current_path.remove(node)
        return True

