class Solution {
 public:
  bool solve(unordered_map<int, vector<int>> &graph) {
    unordered_map<int, bool> visited;
    for (auto &pair : graph) {
      if (!dfs(pair.first, visited, {})) return false;
    }
    return true;
  }

  bool dfs(int node, unordered_map<int, bool> &visited, unordered_set<int> current_path) {
    if (current_path.find(node) != current_path.end())
      return false;
    visited[node] = true;
    current_path.insert(node);
    for (int neighbor : graph[node])
      if (!dfs(neighbor, visited, current_path)) return false;
    current_path.erase(node);
    return true;
  }
};
